const API_URL = "http://localhost:8080/api/auth/login"; // ← una sola URL, sin duplicar /login

export const loginUsuario = async (matricula, password) => {
    try {
        const response = await fetch(API_URL, {  // ← ya no concatenes /Login aquí
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ matricula, password })
        });

        const data = await response.json(); // ← json() porque el backend ya devuelve JSON
        return data.status;

    } catch (error) {
        console.error("Error en conexión:", error);
        return "ERROR_CONEXION";
    }
};
